body.script:
// 양쪽 레이어에 동일한 텍스트를 복사하여 완벽한 오버랩 형성
const textContent = document.getElementById('text-content').innerHTML;
document.getElementById('human-text').innerHTML = textContent;
document.getElementById('ai-text').innerHTML = textContent;

const hudData = document.getElementById('hudData');
let isFrozen = false; 

// 마우스 및 터치 트래킹
function updateCoordinates(clientX, clientY) {
    if(isFrozen) return;

    document.documentElement.style.setProperty('--mouse-x', clientX + 'px');
    document.documentElement.style.setProperty('--mouse-y', clientY + 'px');

    const x = String(clientX).padStart(4, '0');
    const y = String(clientY).padStart(4, '0');
    const hex = Math.floor(Math.random()*0xFFF).toString(16).toUpperCase().padStart(3, '0');

    // X-ray HUD 데이터 업데이트
    hudData.innerHTML = `> X-RAY_SCANNER_ACTIVE<br>> POS: <span class="hl">X_${x} Y_${y}</span><br>> VAL: <span class="hl">0x${hex}</span><br>> PARSING_GEOMETRY...`;
}

document.addEventListener('mousemove', (e) => updateCoordinates(e.clientX, e.clientY));
document.addEventListener('touchmove', (e) => {
    if(e.touches.length > 0) updateCoordinates(e.touches.clientX, e.touches.clientY);
});

// 캡처용 장면 연출
function setScene(sceneType) {
    isFrozen = true;
    document.getElementById('directorMenu').classList.add('active');

    if (sceneType === 1) {
        document.documentElement.style.setProperty('--lens-size', '0vw');
        hudData.innerHTML = `> TARGET_LOST<br>> HUMAN_OPTICS_ONLY`;
    } else if (sceneType === 2) {
        document.documentElement.style.setProperty('--mouse-x', '50vw');
        document.documentElement.style.setProperty('--mouse-y', '50vh');
        document.documentElement.style.setProperty('--lens-size', '30vw');
        hudData.innerHTML = `> X-RAY_LOCKED<br>> POS: <span class="hl">CENTER</span><br>> ALL_NODES_IDENTIFIED`;
    }
}

function resumeInteraction() {
    isFrozen = false;
    document.documentElement.style.setProperty('--lens-size', '20vw');
    document.getElementById('directorMenu').classList.remove('active');
}

// 다운로드 로직
function downloadHTML() {
    const clone = document.documentElement.cloneNode(true);
    const menu = clone.querySelector('#directorMenu');
    if(menu) menu.remove();

    const htmlContent = "<!DOCTYPE html>\n" + clone.outerHTML;
    const blob = new Blob([htmlContent], {type: "text/html"});
    const url = URL.createObjectURL(blob);

    const a = document.createElement('a');
    a.href = url;
    a.download = "SAIOUL_XRAY_Submission.html";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
}

function downloadImage(type) {
    const menu = document.getElementById('directorMenu');
    menu.style.display = 'none';

    setTimeout(() => {
        const options = { 
            quality: 1.0, 
            pixelRatio: 2, 
            style: { cursor: 'default' } 
        };

        const exportFunc = type === 'png' 
            ? htmlToImage.toPng(document.body, options) 
            : htmlToImage.toSvg(document.body, options);

        exportFunc.then(function (dataUrl) {
            const link = document.createElement('a');
            link.download = `SAIOUL_XRAY.${type}`;
            link.href = dataUrl;
            link.click();
            menu.style.display = 'flex'; 
        }).catch(function (error) {
            console.error('Export Error:', error);
            alert('이미지 생성 중 오류가 발생했습니다.');
            menu.style.display = 'flex';
        });
    }, 100);
}
